import socket
import json
import threading

game_state = {'players': [], 'game': {}}

def handle_request(data, client_addr):
    global game_state

    data = data.decode('utf-8')
    if data == 'status':
        response = json.dumps(game_state)
        server_socket.sendto(response.encode('utf-8'), client_addr)

def game_server():
    global server_socket
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
